/* ── Base typography ────────────────────────────────────────────────────────── */
/* In @layer base so Tailwind text-* utilities override these element defaults.
   (Unlayered, they outrank the utilities layer in Tailwind v4 — e.g. a link-
   styled CTA's text-color utility was being ignored.) */
@layer base {
  body {
    font-family: "Raleway", -apple-system, BlinkMacSystemFont, sans-serif;
    line-height: 1.7;
    color: var(--ink-soft);
    background-color: var(--paper);
  }

  h1, h2, h3, h4, h5, h6 {
    font-family: "Fraunces", Georgia, serif;
    font-weight: 400;
    letter-spacing: -0.03em;
    line-height: 1.2;
    color: var(--ink);
    font-variation-settings: var(--fraunces-text);
  }

  h1 {
    line-height: 1.05;
    font-variation-settings: var(--fraunces-display);
  }

  /* terracotta-deep via alias — meets WCAG AA (4.5:1) on paper backgrounds. */
  a { color: var(--text-accent-color); }
}

/* ── Utility classes ────────────────────────────────────────────────────────── */
.fraunces-display  { font-variation-settings: var(--fraunces-display); }
.fraunces-accent   { font-variation-settings: var(--fraunces-accent); font-style: italic; color: var(--text-accent-color); }
.fraunces-text     { font-variation-settings: var(--fraunces-text); }
.fraunces-caption  { font-variation-settings: var(--fraunces-caption); font-style: italic; color: var(--ink-muted); }
